var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"촉수를 끊어!","JPN":"触手を切れ！","ENG":"Sever the tentacles!","TWN":"砍掉所有觸手！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_BOSS_KRAKEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG_02"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"키이라가 본체로 돌격할 수 있는 길을 뚫어라!","JPN":"キーラが本体に突撃できるように道を切り開け！","ENG":"Clear a path so Kiera can charge the main body!","TWN":"替琪伊拉殺向本體開路！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_BOSS_KRAKEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 뻔하지 않은 대답이니까, 마음에 들었거든.","JPN":"キャハハッ！　普通じゃない答えだから、気に入ったんだよ。","ENG":"Kyahaha! It wasn't a boring answer, so I liked it.","TWN":"哈哈哈！回答不落俗套，我喜歡。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"언젠가는 너도, 그런 대답을 할 수 있을 날이 올 거야.","JPN":"いつかはお前にも、そういう風に答えられる日が来るさ。","ENG":"Someday, you'll be able to give an answer like that too.","TWN":"總有一天，妳也能回答出這種答案。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그날을 기대하도록 하지!","JPN":"その日を期待するとしよう！","ENG":"Look forward to that day!","TWN":"讓我們期待那一天！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 그리고 키이라 씨를 보다 보면 그때 봤던 부함장님이 생각나요.","JPN":"ふふ、それにキーラさんを見ていると、あの時お会いした副艦長が思い出されるわ。","ENG":"Fufu... And when I look at Kiera, she reminds me of the first mate I met back then.","TWN":"呵呵，每次看著妳，都會讓我想起那時看到的副船長。"},"stage":{"bg":"VILLAGE1","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그분도 당신과 비슷하지만 다른 말씀을 하셨거든요.","JPN":"あの方も、あなたの言葉と近いけれど、少し違うことをおっしゃっていました。","ENG":"She said something a little like what you said but in her own way.","TWN":"她也說過一句有點類似但又不太一樣的話。"},"stage":{"bg":"VILLAGE1","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"VILLAGE1","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然囉。"},"stage":{"bg":"VILLAGE1","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"피로 뒤범벅된 제 모습마저 포용해 주신 주인님이 계신 것처럼요.","JPN":"血まみれの私の姿でさえ包み込んでくださった、ご主人様のような方がきっと。","ENG":"Just as my master embraced even the blood-soaked version of me.","TWN":"就像主人包容滿身鮮血的我一樣。"},"stage":{"bg":"VILLAGE1","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금 당장 떠올리지 않아도 괜찮아.","JPN":"今すぐ思い出さなくていい。","ENG":"It's okay if you can't think of them right now.","TWN":"現在馬上想不起來也沒關係。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내가 마시멜로를 나눠준 사람을 지키기 위해 싸우듯.","JPN":"オルカがマシュマロをくれた人を守るために戦うように。","ENG":"Just as I fight to protect the ones who shared theirs with me...","TWN":"就像我為了守護給我棉花糖的人而戰一樣，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"언젠가 키이라도 그런 사람들을 지키기 위해 싸우면 되니까.","JPN":"キーラもいつか、そんな人のために戦えばいいから。","ENG":"One day, you can fight to protect the people who shared theirs with you.","TWN":"總有一天，妳也會為了守護那些人而戰。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"벨라미, 내 딸이 다 커서 날 이해하게 되면 전해줘.","JPN":"ベラミー、娘が成長して私のことを理解できるようになったら伝えて。","ENG":"Bellamy. When my daughter grows up enough to understand, tell her this.","TWN":"貝拉米，等我女兒長大能理解我後告訴她，"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"엄마가… 많이 미안하다고 말이야.","JPN":"本当にごめんね……って。","ENG":"Tell her mother... is so, so sorry.","TWN":"媽媽……真的很抱歉。"},"stage":{"bg":"CORRIDOR_04","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"전원! 조금만 더 참고 버텨라!","JPN":"みんな！　もう少し耐えるんだ！","ENG":"Everyone! Hold on just a little longer!","TWN":"全員注意！再撐一下！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리의 공인 카운터가 마지막 일격을 준비하고 있다!","JPN":"我らの公認カウンターが最後の一撃を構えている！","ENG":"Our Official Counter is preparing the final blow!","TWN":"我們的公認制裁者正在準備最後一擊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 제법 좋은 얼굴을 하고 있구나, 키이라.","JPN":"ふふっ。いい顔してるじゃない、キーラ。","ENG":"Fufu, you're wearing quite a nice expression now, Kiera.","TWN":"呵，琪伊拉，妳那表情不錯啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들에게 내일을 꿈꾸게 할 준비는 되었니?","JPN":"人々に明日を夢見させる準備はできたかしら？","ENG":"Are you ready to help people dream of tomorrow?","TWN":"準備好讓大家重新做夢了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"물론이지.","JPN":"言うまでもなく。","ENG":"Of course.","TWN":"那是當然。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적이 될 사람이라면, 이 정도는 가뿐히 해내야 하지 않겠어?","JPN":"大海賊になる人間なら、こんなの朝飯前さ。","ENG":"If I'm going to be a great pirate, something like this should be a breeze, don't you think?","TWN":"想成為大海盜的人，就得做到這樣不是嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 물러나!","JPN":"みんな下がってろ！","ENG":"Everyone, get back!","TWN":"大家退後！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"해일에 휩쓸려 나가도 책임 안 질 테니까!","JPN":"津波に流されても責任取らねえからな！","ENG":"If you get swept away by a tidal wave, it's not my responsibility!","TWN":"要是被海嘯捲走，我可不負責！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"해, 해치웠나?!","JPN":"や、やっつけた！？","ENG":"I-is it dead?!","TWN":"結、結束了嗎？！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리, 우리 이제 그런 말 안 하기로 했잖아.","JPN":"タリー、もうそんなこと言わない約束だっただろ。","ENG":"Tallie... We said we wouldn't say that anymore.","TWN":"塔莉，我們不是講好不說那種話了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하지만… 저렇게 머리가 뻥 뚫렸는데 살아서 움직이란 법은 없겠지.","JPN":"でも……頭にあんなデカい穴が空いたわけだし、もう死んでいると思うよ。","ENG":"But... with a hole that big blown through its head, there's no way it's still moving.","TWN":"可是……它的頭被炸爛了，不可能還活著吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"고생했어. 샤크스.","JPN":"お疲れ、シャークス。","ENG":"Good work, Sharks.","TWN":"辛苦了，大白鯊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"돌아가면 오랜만에 실컷 먹고 마시자고.","JPN":"帰ったら久しぶりに思う存分食って飲もうぜ。","ENG":"Once we get back, let's eat and drink to our hearts' content.","TWN":"回去後我們好好吃一頓喝一頓。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"크, 크라켄이 쓰러진 건가?","JPN":"ク、クラーケンが倒れた？","ENG":"D-did Kraken fall?","TWN":"克、克拉肯倒下了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"해수면이… 낮아지기 시작했어…….","JPN":"海水面が……下がり始めた……","ENG":"The sea level... is beginning to drop...","TWN":"海面……開始下降了……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"승리다!","JPN":"勝った！","ENG":"Victory!","TWN":"贏了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"우리의 승리다!","JPN":"我々の勝利だ！","ENG":"It's our victory!","TWN":"我們贏了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L20_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄 침묵 확인…….","JPN":"クラーケンの沈黙を確認……","ENG":"Kraken silence confirmed...","TWN":"確認克拉肯無聲無息……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"마하 섬이… 드러나고 있습니다.","JPN":"マッハ島が……姿を現しています。","ENG":"Macha Island... is emerging.","TWN":"瑪查島……正在浮出水面。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님, 이건…….","JPN":"シニア様、これは……","ENG":"Senior, this is...","TWN":"Senior，這是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"지난 검은 범람 때 입었던 부상이 완전히 낫지 않은 상태에서 임계치 이상의 충격을 받았나.","JPN":"前回の黒い氾濫で負った傷が完全に回復していない状態で、臨界値以上の衝撃を受けたか。","ENG":"It must've taken a shock past its limit while still injured from the last Black Flood.","TWN":"在上次黑色洪災受的傷還沒完全痊癒，又承受了超過臨界值的衝擊嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"펜릴 소대장이 날린 일격에 반으로 갈라져도 죽지 않았던 녀석이…….","JPN":"フェンリル小隊長が繰り出した一撃で真っ二つになっても死ななかったやつが……","ENG":"The same beast that survived being split in half by the Fenrir Commander's attack...","TWN":"連被芬里爾小隊長劈成兩半都沒死的傢伙……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"드디어…….","JPN":"ついに……","ENG":"Finally...","TWN":"終於……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리의 오랜 숙적이… 바닷속으로 가라앉은 건가?","JPN":"我々の宿敵が……海の底へ沈んだのか？","ENG":"Our longtime nemesis... has sunk to the depths?","TWN":"我們的宿敵……真的沉入海底了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"기쁘신가요?","JPN":"嬉しいですか？","ENG":"Are you happy?","TWN":"你很高興嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"오랜 숙원이었어.","JPN":"長い宿願だった。","ENG":"It was my life's long obsession.","TWN":"這是我多年來的心願。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"앤을 잃고, 해적단을 해산시키고, 시니어로써 살아가면서…….","JPN":"アンを失い、海賊団を解散し、シニアとして生きる間……","ENG":"Losing Anne, disbanding the crew, living on as a Senior...","TWN":"失去安、解散海盜團、以Senior的身分活下來……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"단 한 번도 크라켄에 대한 꿈을 꾸지 않은 적이 없었어.","JPN":"クラーケンの夢を見なかった日はただの一日もなかった。","ENG":"Not once did I fail to dream of Kraken.","TWN":"我沒有一天不夢到克拉肯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"나는 꿈속에서 항상 놈과 싸우며 죽고 죽였다.","JPN":"夢の中で私はやつと戦い、何度も殺し合った。","ENG":"In my dreams, I fought it... died to it... killed it... over and over.","TWN":"在夢裡，我總是在跟克拉肯戰鬥、殺死它。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"진짜 기쁜 순간에는 웃음조차 나오지 않는다더니…….","JPN":"嬉しすぎると笑いすら出なくなるという話は……","ENG":"They say in moments of true joy, you can't even laugh...","TWN":"原來開心的時候笑不出來……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"정말이로군.","JPN":"本当だったのだな。","ENG":"Seems they were right.","TWN":"是真的啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄 덕분인지는 모르겠지만… 우리는 사도들의 습격을 받지 않은 모양이야.","JPN":"クラーケンのおかげかはわからないが……結果的に、使徒の襲撃はなかったようだ。","ENG":"Maybe thanks to Kraken... we weren't targeted by the Apostles.","TWN":"不知道是不是因為克拉肯的關係……我們好像沒有遇到使徒的襲擊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"불행 중 다행이로군.","JPN":"不幸中の幸いだな。","ENG":"A blessing in misfortune, I suppose.","TWN":"這真是不幸中的大幸。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"좋아. 그럼 알파트릭스에게 받은 선로전환기를 가동할 준비를 하지.","JPN":"よし。ではアルファトリックスからもらった線路転換器を稼働する準備を進めよう。","ENG":"All right. Let's prepare to activate the Track Switcher we got from Alphatrix.","TWN":"好，那準備啟動阿爾法崔克斯給我們的線路轉換器。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"알겠습니다. 시니어님!","JPN":"わかりました、シニア様！","ENG":"Understood, sir!","TWN":"我知道了，Senior！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님, 로터스로부터 긴급한 통신 요청입니다.","JPN":"シニア様、ロータスから緊急通信要請です。","ENG":"Sir, we're receiving an urgent call from Lotus.","TWN":"Senior，洛德斯那邊要求緊急通訊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야, 근육남! 거기는 괜찮아?!","JPN":"ねえ、筋肉男！　そこは大丈夫！？","ENG":"Hey, muscle-head! Everything okay over there?!","TWN":"喂，肌肉男！你們那邊還好嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이쪽은 다행히 대균열이 도시와는 좀 떨어진 곳에 있어서 말이지.","JPN":"こちらは幸い、大亀裂が発生した場所が都市と離れていてな。","ENG":"Fortunately, the Grand Dimension Crevice opened a bit away from the city.","TWN":"我們這邊運氣好，大峽谷離城市有點距離。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"도시의 격벽이 모두 파괴되긴 했지만, 시민들은 대부분 대피시켰어.","JPN":"都市の隔壁はすべて破壊されたが、市民はほとんど避難させた。","ENG":"The city's bulwarks are all destroyed, but most of the citizens were evacuated.","TWN":"雖然隔離牆全毀了，但市民大多成功避難。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다, 다행이다…….","JPN":"よ、よかった……","ENG":"Th-thank goodness...","TWN":"太、太好了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"혹시… 선로전환기를 가동한 건 아니겠지?","JPN":"その……線路転換器は稼働してないよね？","ENG":"You... didn't activate the Track Switcher already, did you?","TWN":"你們……該不會已經啟動線路轉換器了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"무슨 문제라도 있나?","JPN":"何か問題でもあるのか？","ENG":"Is there a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그게…….","JPN":"そ、それが……","ENG":"W-well...","TWN":"那、那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하긴, 이론적으로 이터니움이 모이면 차원 계면에 안 좋은 영향을 끼치긴 하죠.","JPN":"確かに、理論的にエタニウムが集まると次元界面に悪影響を及ぼしかねませんね。","ENG":"Well, theoretically, concentrated Eternium can negatively affect the dimension surface.","TWN":"理論上如果聚集太多永恆之金，會對次元界面造成不良影響。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"사전에 알려주셔서 감사합니다, 이졸데 시니어님.","JPN":"事前に伝えてくださってありがとうございます、シニア・イゾルデ。","ENG":"Thank you for the warning, Senior Isolde.","TWN":"謝謝妳提前告訴我們，伊索德Senior。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아니야. 구 관리국의 오퍼레이터인 너라면 분명 가동하기 직전에 알아챘을 거야.","JPN":"ううん。旧管理局オペレーターのあなたなら、きっと稼働する前に気づいたはずだよ。","ENG":"No. As an Old Administration Operator, you would've noticed right before it activated.","TWN":"不，那應該是你這種前管理局領航員……在啟動前就能發現的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아주 기초적인… 이론이니까.","JPN":"とても基礎的な……理論だから。","ENG":"It's very basic... theory.","TWN":"那可是很基礎的……理論。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 문제에 대한 해결 방안은 가지고 온 건가?","JPN":"なら、問題に対する解決策はあるのか？","ENG":"So you brought a solution?","TWN":"所以你們有解決方法了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"설마 내 머리로 그 문제를 해결하라고 하는 건 아니겠지?","JPN":"まさか私の頭で解決しろとは言わないだろうな。","ENG":"You're not expecting me to solve it, are you?","TWN":"該不會是要我用自己的腦袋解決吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당연히 아니지!","JPN":"言わないに決まってるでしょ！","ENG":"Of course not!","TWN":"當然不是！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"안 그래도 우리 쪽 일은 다 끝나서 그쪽에 아티팩트를 보냈어.","JPN":"ちょうどこっちの状況が片付いたから、そっちにアーティファクトを送っといたの。","ENG":"Our work here is done, so we sent the Artifact over to you.","TWN":"我們這邊的工作也差不多告一段落，把神器送過去了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이 상황에 그걸 가져다줄 간 큰 사람들이 있나?","JPN":"こんな状況でそれを運んでくれるほど肝の据わった者がいるのか？","ENG":"In this situation, who would be bold enough to deliver that?","TWN":"在這種情況下還有人有膽送來嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"로터스 사람들도 참 강인하군.","JPN":"ロータスの人は強いな。","ENG":"Lotus people sure are tough.","TWN":"洛德斯那邊的人很堅強嘛。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 얼마나 대기해야 하는 거지?","JPN":"では、あとどれほど待てばいい？","ENG":"How long do we have to wait?","TWN":"那我們還得等多久？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄이 침묵한 지금, 사도가 나타나기 전에 가동하는 게 제일인데…….","JPN":"クラーケンが沈黙した今、使徒が現れる前に稼働させるのがベストなのだが……","ENG":"With Kraken down, the best time to activate it is before the Apostles show...","TWN":"現在克拉肯被壓制，在使徒出現前能啟動最好了…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"5…….","JPN":"5……","ENG":"Five...","TWN":"5……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"5일?","JPN":"5日？","ENG":"Five days?","TWN":"5天？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"4… 3… 2…….","JPN":"4……3……2…….","ENG":"Four... three... two...","TWN":"4……3……2……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"안녕하세요!플라티나익스프레스의배달부,라라예거라고합니다!","JPN":"こんにちは！　プラチナエクスプレスの配達員ララ・イェーガーです！","ENG":"Hello there! I'm Lara Jaeger, your friendly Platinum Express deliverywoman!","TWN":"大家好！我是白金運通的送貨員拉拉·伊格！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"로터스시니어님이갑자기긴급한배송을시키길래잔뜩쫄아있었지뭐예요?그런데있죠,그게사실코핀컴퍼니에서부탁한거더라고요?","JPN":"ロータスのシニアさんに緊急配送を頼まれてめちゃくちゃビビってたんですけどね！　それがですねなんとコフィンカンパニーからの依頼だったんですよね！","ENG":"Senior Lotus suddenly dropped an emergency delivery request on me, so I was totally panicking. Like, heart-going-boom-panicking! But guess what? It turns out the whole thing was actually a request from Coffin Company!","TWN":"洛德斯Senior突然叫我送急件嚇死我了你知道嗎？結果居然是科芬公司委託的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"하핫,이거참휴양지에서겪었던일로이토록저를좋게보시다니,이러다가저진짜오해해버린다고요?아,그건그렇고여기까지오는길에얼마나힘들었는지아세요?바다위를달리는데갑자기어떤일이일어났냐면…….","JPN":"あははっ、まったくも～リゾート地での件でこんなに私を信用してくださるなんて私本当に誤解しちゃいますよ？　あ、それはともかくここまで来るの超大変だったんですからね！　海の上を走ってたら何が起きたかというと……","ENG":"Haha, seriously. If you think that highly of me just because of what happened back at the resort, I'm really going to get the wrong idea, you know? Oh! And speaking of which, do you have any idea how hard it was getting all the way out here? I was sprinting across the ocean and then suddenly this totally wild thing happened...","TWN":"哈哈，他們居然因為我在度假村那次的表現這麼看得起我，我真的會誤會的啦！啊對了，你知道我一路過來多辛苦嗎？我在海面上好好跑著結果突然……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};